// Validate Meta Ads campaign brief payload.
// Required keys · client_id · client_name · industry · campaign_name · objective · daily_budget_cents · landing_url · target_country · personas[] · diferenciador
const body = $input.first().json.body || $input.first().json;
const required = ['client_id', 'client_name', 'industry', 'campaign_name', 'objective', 'daily_budget_cents', 'landing_url', 'target_country'];
const missing = required.filter(k => body[k] === undefined || body[k] === null || body[k] === '');
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}
const validObjectives = ['OUTCOME_AWARENESS','OUTCOME_TRAFFIC','OUTCOME_ENGAGEMENT','OUTCOME_LEADS','OUTCOME_APP_PROMOTION','OUTCOME_SALES'];
if (!validObjectives.includes(body.objective)) {
  throw new Error(`Invalid objective '${body.objective}'. Must be one of: ${validObjectives.join(', ')}`);
}
if (typeof body.daily_budget_cents !== 'number' || body.daily_budget_cents < 100) {
  throw new Error(`daily_budget_cents must be a number >= 100 cents ($1 minimum)`);
}
return [{ json: { ...body, personas: body.personas || [], diferenciador: body.diferenciador || '', brand_assets: body.brand_assets || {} } }];

// Assemble create-campaign payload from agent outputs.
function safeJson(s, fallback) {
  if (!s) return fallback;
  try { return JSON.parse(s); } catch { return fallback; }
}
const brief = $node['Validate Brief'].json;
const mb = safeJson(($node['Agent · media-buyer'].json || {}).response, {});
const cd = safeJson(($node['Agent · creative-director'].json || {}).response, {});
const creatives = Array.isArray(cd.creatives) ? cd.creatives : [];
if (creatives.length === 0) {
  throw new Error('creative-director returned no creatives — abort before Meta call');
}
const payload = {
  client_id: brief.client_id,
  campaign: {
    name: brief.campaign_name,
    objective: brief.objective,
    daily_budget_cents: brief.daily_budget_cents,
    special_ad_categories: brief.special_ad_categories || [],
    buying_type: 'AUCTION',
  },
  adset: {
    name: brief.campaign_name + ' · adset 1',
    targeting: mb.targeting || { geo_locations: { countries: [brief.target_country] } },
    optimization_goal: mb.optimization_goal || 'LINK_CLICKS',
    billing_event: mb.billing_event || 'IMPRESSIONS',
    daily_budget_cents: brief.daily_budget_cents,
  },
  creatives: creatives.slice(0, 3).map(c => ({
    variant_id: c.variant_id || null,
    name: c.title,
    title: c.title,
    body: c.body,
    call_to_action_type: c.call_to_action_type,
    link_url: c.link_url || brief.landing_url,
  })),
  caller: 'n8n-meta-ads-campaign-creator',
};
return [{ json: payload }];
